import{_ as i,o as a,c as l,ag as o}from"./chunks/framework.CNG7EpJN.js";const p=JSON.parse('{"title":"KDSデバイス端末ガイド","description":"","frontmatter":{"title":"KDSデバイス端末ガイド"},"headers":[],"relativePath":"tenant/23-kds-devices.md","filePath":"tenant/23-kds-devices.md"}'),r={name:"tenant/23-kds-devices.md"};function d(e,t,n,s,h,c){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="_23-kdsデバイス端末ガイド" tabindex="-1">23. KDSデバイス端末ガイド <a class="header-anchor" href="#_23-kdsデバイス端末ガイド" aria-label="Permalink to &quot;23. KDSデバイス端末ガイド&quot;">​</a></h1><p>KDS、レジ、ハンディで利用する端末の選び方と設置時の注意点を説明します。</p><h2 id="標準環境のご案内" tabindex="-1">標準環境のご案内 <a class="header-anchor" href="#標準環境のご案内" aria-label="Permalink to &quot;標準環境のご案内&quot;">​</a></h2><p>POSLAの店舗業務端末（KDS・レジ・ハンディ）は、<strong>Android端末 + Google Chrome最新版</strong> を標準環境としています。音声操作、通知音、ホーム画面からの起動などが、Android Chrome で最も安定して動作するためです。</p><p>iPad/Safariでも一部画面は表示できますが、音声コマンドや通知音の動作が安定せず、運用負荷が大きくなるため、業務端末としてはサポート対象外とさせていただいています。</p><h2 id="端末選定-標準-推奨-サポート対象外" tabindex="-1">端末選定（標準/推奨/サポート対象外） <a class="header-anchor" href="#端末選定-標準-推奨-サポート対象外" aria-label="Permalink to &quot;端末選定（標準/推奨/サポート対象外）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>標準環境</th><th>推奨環境</th><th>サポート対象外</th></tr></thead><tbody><tr><td>KDS</td><td>Androidタブレット 10インチ以上、横置き、給電運用、Chrome最新版</td><td>—</td><td>iPad/Safari、Fireタブレット、Chromeを更新できない端末、メーカー独自ブラウザ、アプリ内ブラウザ</td></tr><tr><td>レジ</td><td>Androidタブレット + Chrome最新版、決済端末（Stripe Reader）と安定接続できるもの</td><td>PC（Windows/Mac）+ Chrome最新版</td><td>iPad/Safari、Fireタブレット</td></tr><tr><td>ハンディ</td><td>Androidスマホ/小型Androidタブレット + Chrome最新版</td><td>—</td><td>iPhone/Safari、Fireタブレット、古いAndroid端末</td></tr><tr><td>プリンタ連携</td><td>店舗ネットワークに常時接続できる端末</td><td>—</td><td>—</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Fireタブレット・古いAndroidについて</p><ul><li>Fireタブレット（Amazon）の標準ブラウザ「Silk」はサポート対象外です。</li><li>Android 9以前の古い端末はChromeの自動更新が止まり、音声コマンドや通知音が安定しないためサポート対象外です。</li><li>メーカー独自のブラウザ（Samsung Internet、Huawei Browser、UC Browser など）、アプリ内ブラウザ（LINE等で開いた画面）もサポート対象外です。</li></ul></div><h2 id="設置時の注意" tabindex="-1">設置時の注意 <a class="header-anchor" href="#設置時の注意" aria-label="Permalink to &quot;設置時の注意&quot;">​</a></h2><ul><li>厨房では水、油、熱、衝撃に注意してください。</li><li>端末は営業中に電池切れにならないよう給電してください。</li><li>Wi-Fiの電波が弱い場所には設置しないでください。</li><li>端末ごとに用途を決め、不要な私用アプリを入れない運用を推奨します。</li><li>KDS常時運用では <strong>画面ロックOFF・省電力モードOFF</strong> を設定してください（自動でスリープすると注文受信が止まります）。</li></ul><h2 id="画面が暗くならないようにする補助機能-wake-lock" tabindex="-1">画面が暗くならないようにする補助機能（Wake Lock） <a class="header-anchor" href="#画面が暗くならないようにする補助機能-wake-lock" aria-label="Permalink to &quot;画面が暗くならないようにする補助機能（Wake Lock）&quot;">​</a></h2><p>KDSでは、対応端末で <strong>画面が自動的に暗くなりにくくする補助機能（Wake Lock）</strong> を有効にしています。「KDSを開始」ボタンを押した時点で有効化を試みます。KDSヘッダー右側に状態が表示されます。</p><table tabindex="0"><thead><tr><th>表示</th><th>意味</th></tr></thead><tbody><tr><td>画面維持: 有効</td><td>機能が動作中。画面表示中は暗くなりにくくなります</td></tr><tr><td>画面維持: 端末設定を確認</td><td>端末の省電力設定・画面ロック設定により無効化されています</td></tr><tr><td>画面維持: 未対応</td><td>端末・ブラウザがこの機能に対応していません</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Wake Lock は補助機能で、保証機能ではありません</p><p>端末側の省電力設定・画面ロック設定・OS のバッテリーセーバーによっては、このWake Lock機能が無効化されることがあります。KDS常時運用では、端末側で以下も設定してください。</p><ul><li>画面ロックを「なし」に設定</li><li>省電力モード OFF</li><li>バッテリーセーバー OFF</li><li>画面消灯時間を最長または「なし」に設定（Android: 設定 → ディスプレイ → 画面消灯）</li></ul></div><h2 id="端末専用アカウント" tabindex="-1">端末専用アカウント <a class="header-anchor" href="#端末専用アカウント" aria-label="Permalink to &quot;端末専用アカウント&quot;">​</a></h2><p>KDS、レジ、ハンディなどの店舗備品には、端末専用アカウントでログインします。人の操作が必要な場面では、担当スタッフのPINで誰が操作したかを記録します。</p><h2 id="音声コマンド" tabindex="-1">音声コマンド <a class="header-anchor" href="#音声コマンド" aria-label="Permalink to &quot;音声コマンド&quot;">​</a></h2><p>音声コマンドはAndroidのGoogle Chrome最新版を標準としています。Safari/iPadでは音声コマンドは利用できません。マイク許可、周囲の騒音を確認してください。厨房が騒がしい場合は、手操作と併用してください。</p><h2 id="音声まわりの推奨備品-任意-マイク付き片耳bluetoothヘッドセット" tabindex="-1">音声まわりの推奨備品（任意）: マイク付き片耳Bluetoothヘッドセット <a class="header-anchor" href="#音声まわりの推奨備品-任意-マイク付き片耳bluetoothヘッドセット" aria-label="Permalink to &quot;音声まわりの推奨備品（任意）: マイク付き片耳Bluetoothヘッドセット&quot;">​</a></h2><p>KDSを騒がしい厨房や広い店内で利用する場合は、<strong>マイク付き片耳Bluetoothヘッドセット</strong>（飲食店の現場では「インカム」とも呼ばれます）の併用をおすすめします。通知音や音声案内を耳元で直接聞き取りやすくなり、音声コマンドを使う場合のマイク入力も安定しやすくなります。POSLAの必須機器ではなく、店舗環境に応じた推奨備品としてご検討ください。</p><h3 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h3><ul><li>厨房やホールの騒音の中でも、KDSの通知音や音声案内を聞き取りやすくする</li><li>音声コマンドを使う場合、マイク入力を安定させやすくする</li><li>片耳タイプであれば、周囲の声・来客対応・安全確認も残しやすくする</li></ul><h3 id="選び方の目安" tabindex="-1">選び方の目安 <a class="header-anchor" href="#選び方の目安" aria-label="Permalink to &quot;選び方の目安&quot;">​</a></h3><ul><li>マイク付きの片耳Bluetoothヘッドセットをお選びください</li><li>長時間装着しても疲れにくい形状・重さのもの</li><li>営業時間中に必要な連続使用時間を確保できるもの（予備バッテリーや交互充電も検討）</li><li>ノイズ低減マイク付きだと、音声コマンドの認識がさらに安定しやすくなります</li><li>厨房で使う場合は、防水・防塵・清掃しやすさもあわせて確認してください</li><li>完全ワイヤレスの両耳イヤホンは、周囲の音をふさぎやすく紛失もしやすいため、業務利用の標準推奨にはしていません</li></ul><h3 id="運用上の注意" tabindex="-1">運用上の注意 <a class="header-anchor" href="#運用上の注意" aria-label="Permalink to &quot;運用上の注意&quot;">​</a></h3><ul><li>営業前に <strong>Bluetooth接続・音量・マイク許可</strong> を確認してください</li><li><strong>充電残量</strong> を確認し、必要に応じて予備バッテリーや充電ケーブルを準備してください</li><li>1台のKDS端末に接続するヘッドセットを決めておくと、接続切替の混乱を避けられます</li><li>共有して使う場合は衛生管理を行ってください。できれば <strong>個人別または端末別</strong> に管理することをおすすめします</li><li>Bluetooth接続が不安定な場合に備えて、KDS画面のボタンによる <strong>手操作にいつでも戻せる</strong> 状態にしておいてください</li></ul><div class="tip custom-block"><p class="custom-block-title">動作保証について</p><p>お使いの端末・ヘッドセット・店舗のWi-Fi/Bluetooth環境の組み合わせによって接続性は変わるため、POSLAでは特定のBluetooth機器の動作を保証していません。導入前に、実際の営業環境で連続利用テストを行ってください。</p></div><h2 id="通知を受け取る-補助機能" tabindex="-1">通知を受け取る（補助機能） <a class="header-anchor" href="#通知を受け取る-補助機能" aria-label="Permalink to &quot;通知を受け取る（補助機能）&quot;">​</a></h2><p>KDS / レジ / ハンディの画面ヘッダ右側に「通知: 未設定 (タップで許可)」と表示されている場合、タップすると通知許可ダイアログが出ます。<strong>Android Chrome 端末で PWA をインストール済み</strong> の場合、お客様の呼び出しなど重要な業務通知をホーム画面の通知欄から受け取れます。</p><div class="warning custom-block"><p class="custom-block-title">通知は補助機能です</p><ul><li>通知が届かなかった場合に備えて、KDS の画面表示やハンディの呼び出しバナーなど、画面側の確認は引き続き行ってください</li><li>通知が来ない場合の確認: <ul><li>Android Chrome の最新版か（iPhone / iPad / Safari は業務端末の標準環境外）</li><li>PWA をホーム画面に追加（インストール）しているか</li><li>通知許可が ON か（Android: 設定 → アプリ → POSLA → 通知）</li><li>省電力モード / バッテリーセーバーで通知が制限されていないか</li><li>端末がオンラインか</li></ul></li></ul></div><p>ホーム画面のアイコンには未対応の場合もありますが、KDS の呼び出し件数や、ハンディの呼び出し件数が <strong>バッジ (赤い数字)</strong> として表示される場合があります（端末・ブラウザの対応状況によります）。</p><h2 id="通信が一時的に切れた場合の挙動-補助機能" tabindex="-1">通信が一時的に切れた場合の挙動（補助機能） <a class="header-anchor" href="#通信が一時的に切れた場合の挙動-補助機能" aria-label="Permalink to &quot;通信が一時的に切れた場合の挙動（補助機能）&quot;">​</a></h2><p>KDS / レジ / ハンディでは、Wi-Fi が一時的に不安定になっても <strong>画面が真っ白になることを防ぐ補助機能</strong> が入っています。</p><ul><li>直前に取得できた注文一覧・呼び出し・テーブル状況・会計対象 などが画面にそのまま残ります</li><li>画面上部に黄色いバナーで「<strong>古いデータを表示中です。操作は通信復帰後に行ってください。</strong>」と表示されます</li><li>この状態では <strong>調理開始 / 完成 / 提供済 / 取消 / 会計 / 返金 / 領収書発行 / 注文送信</strong> などの操作はできません。ボタンは無効化されるか、押すとエラー表示されます</li><li><strong>通信が復帰すると緑のバナーで「通信が復帰しました」と表示</strong>され、最新情報が自動で再取得されます</li></ul><div class="warning custom-block"><p class="custom-block-title">オフライン中に業務を進めないでください</p><p>通信が切れている間は、古い注文情報のまま新たに会計・注文送信・提供済み更新などを行うと <strong>二重処理や記録漏れの原因になります</strong>。POSLA はオフライン中の操作を意図的に受け付けません。通信が復帰してから操作してください。</p></div><div class="tip custom-block"><p class="custom-block-title">「再取得」ボタン</p><p>古いデータ表示中のバナー内に「再取得」ボタンがあります。手動で最新情報を取りに行きたい場合に使います (画面によっては一度リロードが走ります)。</p></div><h2 id="ホーム画面に追加する-pwaインストール" tabindex="-1">ホーム画面に追加する（PWAインストール） <a class="header-anchor" href="#ホーム画面に追加する-pwaインストール" aria-label="Permalink to &quot;ホーム画面に追加する（PWAインストール）&quot;">​</a></h2><p>業務端末では、POSLAをホーム画面に追加して1タップで起動できるようにすることを推奨します。</p><ul><li><strong>Android Chrome（推奨）</strong>: アドレスバーに「アプリをインストール」または画面内の「POSLAをインストール」ボタンが表示された場合はタップ。表示されない場合はメニュー（︙）→「ホーム画面に追加」/「アプリをインストール」。</li><li><strong>iOS Safari</strong>: ブラウザ仕様によりWeb側からのインストールダイアログは表示できないため、Safariの共有メニュー → 「ホーム画面に追加」で追加します（業務端末としてはサポート対象外）。</li></ul><div class="tip custom-block"><p class="custom-block-title">顧客セルフメニューはインストール不要</p><p>お客様向けのセルフメニュー、予約、テイクアウト画面は1回限りの利用を想定しているため、PWAインストールは行わずブラウザのまま利用してください。</p></div><h2 id="起動前チェックリスト" tabindex="-1">起動前チェックリスト <a class="header-anchor" href="#起動前チェックリスト" aria-label="Permalink to &quot;起動前チェックリスト&quot;">​</a></h2><p>KDS/レジ/ハンディの開店前チェック項目です。詳しい操作手順は「Part 0: 準備」「Part 1: 毎日の営業」をご覧ください。</p><ul><li>[ ] Android端末か（iPad/Safariはサポート対象外）</li><li>[ ] Google Chrome最新版か（Chromeのバージョン更新を確認）</li><li>[ ] PWAとしてホーム画面に追加済みか（任意。1タップ起動を推奨）</li><li>[ ] マイク権限が許可されているか（KDS音声コマンド利用時）</li><li>[ ] 通知音テストができるか（KDS起動オーバーレイの「タップして開始」を1回押す）</li><li>[ ] Wi-Fi接続があるか（端末右上のWi-Fiアイコンを確認）</li><li>[ ] 画面ロックOFF・省電力モードOFF（KDS常時運用時）</li><li>[ ] KDS画面が常時前面で開かれているか（他アプリへ切り替わっていないか）</li><li>[ ] （任意）マイク付き片耳Bluetoothヘッドセットを使う場合、Bluetooth接続・音量・マイク許可・充電残量を確認</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>画面がスリープする</td><td>端末の自動ロック設定を「なし」にしてください。Androidの場合は「設定 → ディスプレイ → 画面消灯」を最大に。</td></tr><tr><td>Wi-Fiが切れる</td><td>設置場所とアクセスポイントを確認してください。</td></tr><tr><td>音声が認識されない</td><td>AndroidのGoogle Chrome最新版か、マイク許可、周囲の騒音を確認してください。Safari/iPadでは音声コマンドは利用できません。</td></tr><tr><td>通知音が鳴らない</td><td>画面起動時の「タップして開始」オーバーレイを1回タップしてください。Safariは通知音が安定しないためAndroid Chromeをお試しください。</td></tr><tr><td>端末を入れ替えたい</td><td>新しい端末で端末専用アカウントにログインしてください。</td></tr><tr><td>「標準サポート対象外」のバナーが出る</td><td>標準環境（Android端末 + Chrome最新版）への入れ替えをご検討ください。閉じるボタンで一時的に消すことはできます。</td></tr><tr><td>Bluetoothヘッドセットの音が出ない / マイクが反応しない</td><td>Bluetooth接続を確認し、必要なら再ペアリングしてください。充電残量、端末側の音声出力先（スピーカー/ヘッドセット）、マイク許可もあわせてご確認ください。接続が安定しない場合は、KDS画面の手操作に戻して運用を続けてください。</td></tr></tbody></table>',45)])])}const b=i(r,[["render",d]]);export{p as __pageData,b as default};
